package sn.gestionimmobiliere.backend.identity.application;
import java.nio.charset.StandardCharsets;import java.time.*;import java.util.Date;import javax.crypto.SecretKey;import org.springframework.stereotype.Service;import io.jsonwebtoken.*;import io.jsonwebtoken.security.Keys;import sn.gestionimmobiliere.backend.identity.domain.AppUser;
@Service public class JwtService{private final SecurityProperties properties;private final SecretKey key;public JwtService(SecurityProperties p){properties=p;key=Keys.hmacShaKeyFor(p.jwtSecret().getBytes(StandardCharsets.UTF_8));}public String create(AppUser u){Instant now=Instant.now();return Jwts.builder().subject(u.getId().toString()).claim("organization_id",u.getOrganizationId().toString()).claim("role",u.getRole().name()).claim("email",u.getEmail()).issuedAt(Date.from(now)).expiration(Date.from(now.plusSeconds(properties.tokenValidityMinutes()*60))).signWith(key).compact();}public Claims parse(String token){return Jwts.parser().verifyWith(key).build().parseSignedClaims(token).getPayload();}}
